import React from 'react';
import { Input, SearchInput, MoneyInput } from '@linm-soft/common-components';
import { AccountSearchInput, erpFinanceAccountSearchApi } from '../../../../../components/search';
import { formatAccountDisplay } from '../../../../../components/search/accountSearchApi';
import {
  DEPARTMENT_PLACEHOLDER_OPTION,
  resolveDepartmentName,
} from '../../../../../utils/departmentField';
import type { TamUngFormViewModel } from '../hooks/useTamUngFormController';

export const TamUngLinesSection: React.FC<{ vm: TamUngFormViewModel }> = ({ vm }) => {
  const {
    labels,
    tid,
    styles: df,
    viewSectionClass,
    lines,
    fieldErrors,
    updateLine,
    removeLine,
    addBlankLine,
    isReadOnly,
    isViewMode,
    ph,
    searchDisabled,
    fieldLockProps,
    departmentSearchConfig,
    departmentOptions,
  } = vm;

  return (
    <div
      className={[df.section, viewSectionClass].filter(Boolean).join(' ')}
      id={tid('section-lines')}
      data-testid={tid('section-lines')}
    >
      <h2 className={df.sectionTitle}>{labels.sectionLines}</h2>
      <div className={df.tableWrapper}>
        <table className={df.linesTable}>
          <thead>
            <tr>
              <th className={df.thAccount}>{labels.debitAccount}</th>
              <th className={df.thAmount}>{labels.amount}</th>
              <th>{labels.costCenter}</th>
              <th className={df.thDesc}>{labels.lineDescription}</th>
              {!isReadOnly && <th className={df.thDel} />}
            </tr>
          </thead>
          <tbody>
            {lines.map((line, idx) => (
              <tr key={idx} data-testid={tid(`line-${idx}`)}>
                <td id={tid(`line-${idx}-account`)} data-testid={tid(`line-${idx}-account`)}>
                  <AccountSearchInput
                    api={erpFinanceAccountSearchApi}
                    className={df.lineAccountSearch}
                    value={line.accountCode}
                    primaryDisplay={formatAccountDisplay(line.accountCode, line.accountName)}
                    error={fieldErrors.lines?.[idx]?.accountCode}
                    onChange={a => updateLine(idx, { accountCode: a.code, accountName: a.name })}
                    onClear={() => updateLine(idx, { accountCode: '', accountName: '' })}
                    showLabel={false}
                    showSecondaryInput={false}
                    placeholder={ph(labels.phDebitAccount)}
                    disabled={searchDisabled}
                  />
                </td>
                <td id={tid(`line-${idx}-amount`)} data-testid={tid(`line-${idx}-amount`)}>
                  <MoneyInput
                    value={Number(line.amount)}
                    error={fieldErrors.lines?.[idx]?.debitAmount}
                    onChange={amount => updateLine(idx, { amount })}
                    {...fieldLockProps}
                  />
                </td>
                <td data-testid={tid(`line-${idx}-costCenter`)}>
                  <SearchInput
                    config={departmentSearchConfig}
                    className={isViewMode ? df.searchViewOnly : df.lineAccountSearch}
                    value={line.costCenterCode}
                    primaryDisplay={line.costCenterCode}
                    secondaryDisplay={resolveDepartmentName(line.costCenterCode, departmentOptions)}
                    onChange={d => updateLine(idx, { costCenterCode: d.code })}
                    onClear={() => updateLine(idx, { costCenterCode: '' })}
                    showLabel={false}
                    placeholder={ph(DEPARTMENT_PLACEHOLDER_OPTION.label)}
                    disabled={searchDisabled}
                  />
                </td>
                <td data-testid={tid(`line-${idx}-description`)}>
                  <Input
                    value={line.description}
                    onChange={e => updateLine(idx, { description: e.target.value })}
                    placeholder={ph(labels.phLineDescription)}
                    {...fieldLockProps}
                  />
                </td>
                {!isReadOnly && (
                  <td>
                    <button
                      type="button"
                      className={df.btnDeleteLine}
                      onClick={() => removeLine(idx)}
                      title="Xóa dòng"
                      disabled={lines.length <= 1}
                    >
                      <i className="fas fa-trash-alt" aria-hidden="true" />
                    </button>
                  </td>
                )}
              </tr>
            ))}
          </tbody>
        </table>
      </div>
      {!isReadOnly && (
        <button
          type="button"
          className={df.btnAddLine}
          data-testid={tid('add-line-btn')}
          onClick={addBlankLine}
        >
          {labels.addLine}
        </button>
      )}
    </div>
  );
};
